clean_code:
from zipline.api import order_target_percent

def rebalance(context, data):
    for asset in context.portfolio_assets:
        weight = context.target_weights.get(asset, 0)
        # Always check before ordering
        if data.can_trade(asset):
            order_target_percent(asset, weight)
        else:
            # Log that we couldn't trade this asset
            print(f'Cannot trade {asset} on this date')
